import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';

function Accueil() {
  const [texte, setTexte] = useState('');
  const phrase = "Ingénieur Réseaux & Systèmes";

  useEffect(() => {
    let i = 0;
    const interval = setInterval(() => {
      setTexte(phrase.slice(0, i));
      i++;
      if (i > phrase.length) clearInterval(interval);
    }, 80);
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={{background: '#000000', minHeight: '100vh'}}>

      {/* HERO */}
      <section style={{
        minHeight: '100vh', display: 'flex', flexDirection: 'column',
        justifyContent: 'center', alignItems: 'center', textAlign: 'center',
        padding: '100px 20px',
        background: 'radial-gradient(ellipse at center, #0a1a0a 0%, #000000 70%)'
      }}>
        <motion.div
          initial={{opacity: 0, scale: 0.5}}
          animate={{opacity: 1, scale: 1}}
          transition={{duration: 0.8}}
          style={{fontSize: '80px', marginBottom: '20px'}}
        >
          🔥
        </motion.div>

        <motion.h1
          initial={{opacity: 0, y: -50}}
          animate={{opacity: 1, y: 0}}
          transition={{duration: 0.8, delay: 0.3}}
          style={{fontSize: '52px', color: '#ffd700', letterSpacing: '4px', marginBottom: '15px'}}
        >
          BBRS Morphix IT
        </motion.h1>

        <motion.p
          initial={{opacity: 0}}
          animate={{opacity: 1}}
          transition={{duration: 1, delay: 0.6}}
          style={{fontSize: '24px', color: '#00aa00', letterSpacing: '2px', marginBottom: '10px'}}
        >
          {texte}<span style={{animation: 'blink 1s infinite'}}>|</span>
        </motion.p>

        <motion.p
          initial={{opacity: 0, y: 20}}
          animate={{opacity: 1, y: 0}}
          transition={{duration: 0.8, delay: 1}}
          style={{fontSize: '18px', color: '#cccccc', marginBottom: '40px', maxWidth: '600px'}}
        >
          Transformons vos besoins informatiques en solutions concrètes
        </motion.p>

        <motion.div
          initial={{opacity: 0, y: 30}}
          animate={{opacity: 1, y: 0}}
          transition={{duration: 0.8, delay: 1.2}}
          style={{display: 'flex', gap: '20px', flexWrap: 'wrap', justifyContent: 'center'}}
        >
          <Link to="/services" style={{
            background: '#00aa00', color: '#ffffff', padding: '15px 40px',
            borderRadius: '30px', textDecoration: 'none', fontSize: '16px',
            fontWeight: 'bold', transition: 'all 0.3s'
          }}>
            Voir mes services
          </Link>
          <Link to="/contact" style={{
            background: 'transparent', color: '#ffd700', padding: '15px 40px',
            borderRadius: '30px', textDecoration: 'none', fontSize: '16px',
            fontWeight: 'bold', border: '2px solid #ffd700', transition: 'all 0.3s'
          }}>
            Me contacter
          </Link>
        </motion.div>

        {/* Particules */}
        <div style={{position: 'absolute', top: 0, left: 0, width: '100%', height: '100vh', overflow: 'hidden', pointerEvents: 'none', zIndex: 0}}>
          {[...Array(15)].map((_, i) => (
            <motion.div
              key={i}
              style={{
                position: 'absolute',
                width: '4px', height: '4px',
                background: i % 2 === 0 ? '#00aa00' : '#ffd700',
                borderRadius: '50%',
                left: `${Math.random() * 100}%`,
                top: `${Math.random() * 100}%`,
              }}
              animate={{y: [0, -30, 0], opacity: [0.3, 1, 0.3]}}
              transition={{duration: 3 + Math.random() * 3, repeat: Infinity, delay: Math.random() * 3}}
            />
          ))}
        </div>
      </section>

      {/* STATS */}
      <section style={{
        padding: '60px 50px', background: '#0a0a0a',
        borderTop: '2px solid #00aa00', borderBottom: '2px solid #00aa00'
      }}>
        <div style={{display: 'flex', justifyContent: 'center', gap: '60px', flexWrap: 'wrap'}}>
          {[['🎓', 'Master', 'Réseaux & Systèmes'], ['🔒', 'Kali Linux', 'Cybersécurité'], ['🌍', 'Remote', 'Disponible'], ['⚡', 'Réactif', 'Support rapide']].map(([icon, titre, desc]) => (
            <motion.div
              key={titre}
              initial={{opacity: 0, y: 20}}
              whileInView={{opacity: 1, y: 0}}
              transition={{duration: 0.5}}
              style={{textAlign: 'center'}}
            >
              <div style={{fontSize: '40px', marginBottom: '10px'}}>{icon}</div>
              <h3 style={{color: '#ffd700', fontSize: '20px', marginBottom: '5px'}}>{titre}</h3>
              <p style={{color: '#aaaaaa', fontSize: '14px'}}>{desc}</p>
            </motion.div>
          ))}
        </div>
      </section>

      {/* APERÇU SERVICES */}
      <section style={{padding: '80px 50px', background: '#000000', textAlign: 'center'}}>
        <motion.h2
          initial={{opacity: 0}}
          whileInView={{opacity: 1}}
          transition={{duration: 0.8}}
          style={{fontSize: '40px', color: '#ffd700', marginBottom: '10px', letterSpacing: '3px'}}
        >
          Mes Services
        </motion.h2>
        <p style={{color: '#aaaaaa', marginBottom: '50px'}}>Des solutions adaptées à vos besoins</p>

        <div style={{display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '25px', maxWidth: '1100px', margin: '0 auto'}}>
          {[
            ['🌐', 'Réseau à distance', 'Configuration VPN, administration réseau, diagnostic de pannes.'],
            ['💻', 'Systèmes à distance', 'Administration Linux/Windows, gestion des utilisateurs.'],
            ['🔧', 'Assistance sur site', 'Installation WiFi, dépannage, configuration routeurs à Dakar.'],
            ['🌍', 'Création web', 'Sites vitrines et portfolios avec WordPress.']
          ].map(([icon, titre, desc]) => (
            <motion.div
              key={titre}
              initial={{opacity: 0, scale: 0.9}}
              whileInView={{opacity: 1, scale: 1}}
              whileHover={{scale: 1.05, boxShadow: '0 0 25px #00aa00'}}
              transition={{duration: 0.3}}
              style={{
                background: '#0a0a0a', border: '1px solid #00aa00',
                borderRadius: '15px', padding: '30px'
              }}
            >
              <div style={{fontSize: '40px', marginBottom: '15px'}}>{icon}</div>
              <h3 style={{color: '#00aa00', marginBottom: '10px'}}>{titre}</h3>
              <p style={{color: '#cccccc', fontSize: '14px', lineHeight: '1.6'}}>{desc}</p>
            </motion.div>
          ))}
        </div>

        <motion.div
          initial={{opacity: 0}}
          whileInView={{opacity: 1}}
          style={{marginTop: '40px'}}
        >
          <Link to="/services" style={{
            background: 'transparent', color: '#00aa00',
            padding: '12px 35px', borderRadius: '30px',
            textDecoration: 'none', border: '2px solid #00aa00',
            fontSize: '16px', fontWeight: 'bold'
          }}>
            Voir tous mes services →
          </Link>
        </motion.div>
      </section>
    </div>
  );
}

export default Accueil;
